INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Remux', '\b(Remux)\b', NULL, 'A remux is a digital video file that maintains the exact quality of the original source (like a Blu-ray or DVD) by copying the video and audio streams without re-encoding them, essentially creating a perfect 1:1 copy. Think of it like carefully transferring the contents of a Blu-ray disc into a more convenient container file format (typically MKV), similar to pouring fine wine from its bottle into a decanter without changing the wine itself.');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Repack1', '\b(re(pack|rip)|proper)\b', NULL, 'Matches ''PROPER'' or ''REPACK'' or ''RERIP'' only when they appear after a year (4 digits) but not before one.

* `(?<=.*?\d{4}.*?)` - look for a 4-digit number before
* `\b(re(pack|rip)|proper)\b` - match proper/repack/rerip');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Repack2', '\b(real[\s.]?(re(pack|rip)|proper)|(re(pack|rip)|proper)2)\b', NULL, 'Matches either "real" (with optional space/dot) followed by proper/repack/rerip, or proper2/repack2/rerip2

* `\b(real[\s.]?(re(pack|rip)|proper)` - match real followed by proper/repack/rerip
* `|(re(pack|rip)|proper)2)\b` - or match proper2/repack2/rerip2');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Repack3', '\b(real[\s.]?real[\s.]?(re(pack|rip)|proper)|(re(pack|rip)|proper)3)\b', NULL, 'Matches either "real real" (with optional space/dot between words) followed by proper/repack/rerip, or proper3/repack3/rerip3

* `\b(real[\s.]?real[\s.]?(re(pack|rip)|proper)` - match real real followed by proper/repack/rerip
* `|(re(pack|rip)|proper)3)\b` - or match proper3/repack3/rerip3');
