INSERT OR IGNORE INTO "custom_formats" ("name", "description", "include_in_rename") VALUES ('DVD', 'The DVD format, or Digital Versatile Disc, is an optical disc storage medium widely used for video, audio, and data storage. It offers a standard capacity of 4.7 GB for single-layer discs and up to 8.5 GB for dual-layer discs, making it suitable for movies, software, and backups. DVDs provide a resolution of 720x480 (NTSC) or 720x576 (PAL) for video and support Dolby Digital or DTS audio for high-quality sound. They are compatible with standalone DVD players, computer drives, and gaming consoles, offering broad accessibility while requiring a physical disc for playback.', 0);
INSERT OR IGNORE INTO "custom_formats" ("name", "description", "include_in_rename") VALUES ('DVD Remux', 'A DVD Remux is a direct rip of a DVD''s content without any re-encoding, preserving the original video, audio, and subtitle quality. It retains the exact resolution, bitrate, and format of the DVD, ensuring no loss in fidelity compared to the source.', 0);
