INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('1080p Balanced', '1080p Balanced targets consistent & immutable 1080p **WEB-DLs** using the Streaming Source and Audio Formats to determine the level of Transparency.

- Average Movie Sizes ~ 4 to 8gb per Movie
- Movie Quality Ranking ~ 6/10
- Average TV Sizes ~ 2 to 4gb per Episode
- TV Quality Ranking ~ 7/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('1080p Compact', '1080p Compact targets low to medium quality x265 Bluray and WEB Encodes. 

- Average Movie Sizes ~ 3 to 6gb per Movie
- Movie Quality Ranking ~ 4/10
- Average TV Sizes ~ 1 to 2gb per Episode
- TV Quality Ranking ~ 4/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('1080p Efficient', '1080p Efficient targets high quality x265 Bluray and WEB Encodes

- Average Movie Sizes ~ 6 to 12gb per Movie
- Movie Quality Ranking ~ 7/10
- Average TV Sizes ~ 2 to 3gb per Episode
- TV Quality Ranking ~ 6/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('1080p Quality', '1080p Quality utilizes the [**Golden Popcorn Performance Index**](https://dictionarry.dev/wiki/gppi) to target **Transparent** x264 1080p Encodes. 

- Average Movie Sizes ~ 10 to 15gb per Movie
- Movie Quality Ranking ~ 8/10
- Average TV Sizes ~ 4 to 8gb per Episode
- TV Quality Ranking ~ 8/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('1080p Quality HDR', '1080p Quality HDR utilizes the [**Golden Popcorn Performance Index**](https://dictionarry.dev/wiki/gppi) to target **Transparent x265 HDR** 1080p Encodes. 

- Average Movie Sizes ~ 10 to 20gb per Movie
- Movie Quality Ranking ~ 9/10
- Average TV Sizes ~ 4 to 10gb per Episode
- TV Quality Ranking ~ 9/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('1080p Remux', '1080p Remux utilizes **Audio Formats** to prioritise high quality Lossless HD Blurays with a fallback to Transparent Bluray Encodes.

- Average Movie Sizes ~ 20 to 30gb per Movie
- Movie Quality Ranking ~ 10/10
- Average TV Sizes ~ 6 to 12gb per Episode
- TV Quality Ranking ~ 10/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('2160p Balanced', '2160p Balanced targets consistent & immutable 2160p **WEB-DLs w/ Lossy Audio**. 

- Average Movie Sizes ~ 15 to 30gb per Movie
- Movie Quality Ranking ~ 8/10
- Average TV Sizes ~ 5 to 15gb per Episode
- TV Quality Ranking ~ 8/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('2160p Efficient', '2160p Efficient targets consistent & immutable 2160p **WEB-DLs w/ Lossy Audio**. Specialized Fallback to 1080p Efficient

- Average Movie Sizes ~ 15 to 30gb per Movie
- Movie Quality Ranking ~ 6/10
- Average TV Sizes ~ 4 to 12gb per Episode
- TV Ranking ~ 6/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('2160p Quality', '2160p Quality utilizes the [**Encode Efficiency Index**](https://dictionarry.dev/wiki/eei) metric at a 60% target ratio to prioritize **Transparent** x265 4K Encodes

- Average Movie Sizes ~ 30 to 50gb per Movie
- Movie Quality Ranking ~ 9/10
- Average TV Sizes ~ 10 to 20gb per Episode
- TV Quality Ranking ~ 9/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('2160p Remux', '2160p Remux utilizes **Video / Audio Formats** to prioritise high quality lossless copies of UHD Blurays.

- Average Movie Sizes ~ 40 to 60gb per Movie
- Movie Quality Ranking ~ 10/10
- Average TV Sizes ~ 15 to 30gb per Episode
- TV Quality Ranking ~ 10/10', 1, 200000, 1000000, 1);
INSERT OR IGNORE INTO "quality_profiles" ("name", "description", "upgrades_allowed", "minimum_custom_format_score", "upgrade_until_score", "upgrade_score_increment") VALUES ('720p Quality', '720p Quality utilizes the [**Golden Popcorn Performance Index**](https://dictionarry.dev/wiki/gppi) to target **Transparent** x264 720p Encodes. 

- Average Movie Sizes ~ 4 to 8gb per Movie
