INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Canadian Broadcasting Corporation', '\b(CBC)\b', NULL, 'The Canadian Broadcasting Corporation (French: Société Radio-Canada), branded as CBC/Radio-Canada, is the Canadian public broadcaster for both radio and television. It is a Crown corporation that serves as the national public broadcaster, with its English-language and French-language service units known as CBC and Radio-Canada, respectively.');
