INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Crave [Dumpstarr]', '\b(?:CRAV|(?:CRAVE)(?=\s*.(?:WEB-?DL|WEBRIP)))\b', NULL, 'Crave (originally CraveTV) is a Canadian subscription video on demand service. The service competes directly with other subscription-based over-the-top streaming services operating in Canada, primarily against American-based services.');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Criterion', '\b(CC)\b', NULL, '');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Criterion Release Title', '\b(Criterion)\b', NULL, '');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Criterion Channel', '\b(CRiT)\b', NULL, 'The Criterion Channel is a subscription-based streaming service launched on April 8, 2019, by The Criterion Collection. Available in the United States and Canada, it features a rich library of films, including Criterion Collection releases with special features, curated playlists, temporarily licensed titles, and original content such as academic overviews and introductions. The Channel also showcases Janus-owned titles not yet available on physical media and maintains a collaborative relationship with Warner Bros. Discovery''s Max platform. Perfect for cinephiles, the service brings a curated cinematic experience to the digital space.');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('Criterion Group', '^(Criterion)$', NULL, '');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('CTR [Dumpstarr]', '\b(CTR)\b', NULL, '');
INSERT OR IGNORE INTO "regular_expressions" ("name", "pattern", "regex101_id", "description") VALUES ('CW Network', '\b(CWS)\b', NULL, 'The CW Network, LLC (commonly referred to as the CW or simply CW) is an American commercial broadcast television network which is controlled by Nexstar Media Group through a 75% ownership interest. The network''s name is derived from the first letters of the names of its two founding co-owners CBS Corporation and Warner Bros. Nexstar acquired a 75% controlling stake in the network on October 3, 2022, with Paramount Skydance and Warner Bros. Discovery (CBS Corporation and Warner Bros.''s respective successor companies) each retaining a 12.5% ownership stake.');
